-- ============================================================================
-- MDLH Gold Layer SQL - Databricks Lowercase Version
-- ============================================================================

CREATE CATALOG IF NOT EXISTS ATLAN;

CREATE SCHEMA IF NOT EXISTS ATLAN.ATLAN_GOLD;

USE ATLAN_CONTEXT_STORE.entity_metadata;
CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.TAGS 
(
    asset_guid COMMENT 'The asset’s globally-unique identifier',
    asset_type COMMENT 'The asset’s type',
    tag_guid COMMENT 'The tag’s globally-unique identifier',
    tag_name COMMENT 'The tag’s name',
    tag_value COMMENT 'The tag’s value',
    tag_connector_name COMMENT 'The type of connector where this tag originates from, if applicable',
    propagate COMMENT 'Whether or not the tag propagates through hierarchy or parent-child relationships (True or False)'
)
COMMENT 'Information about tagged assets in Atlan'
AS
SELECT
    entityguid AS asset_guid,
    entitytypename AS asset_type,
    tagguid AS tag_guid,
    tagname AS tag_name,
    tagvalue AS tag_value,
    tagconnectorname AS tag_connector_name,
    propagate AS propagate
FROM tagrelationship;


CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.CUSTOM_METADATA 
(
    asset_guid COMMENT 'The asset’s globally-unique identifier', 
    asset_type COMMENT 'The asset’s type',
    custom_metadata_guid COMMENT 'The globally-unique identifier for the custom metadata definition',
    custom_metadata_name COMMENT 'The name of the custom metadata definition',
    attribute_name COMMENT 'The name of the custom metadata attribute',
    attribute_value COMMENT 'The value of the custom metadata attribute',
    status COMMENT 'The status of the process custom metadata (active/inactive)'
)
COMMENT 'Information about custom metadata in Atlan'
AS
SELECT
    entityguid AS asset_guid, 
    entitytypename AS asset_type,
    setguid AS custom_metadata_guid,
    setdisplayname AS custom_metadata_name,
    attributedisplayname AS attribute_name,
    attributevalue AS attribute_value,
    status AS status 
FROM custommetadatarelationship;

CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.DATA_MESH_DETAILS
(
    guid COMMENT 'The asset’s globally-unique identifier',
    asset_type COMMENT 'Type of Data Mesh asset. Supported values: DataDomain, DataProduct',
    data_products COMMENT 'List of GUIDs for data products that exist within this data domain',
    parent_domain COMMENT 'GUID of the parent data domain in which this sub-data domain exists',
    stakeholders COMMENT 'List of GUIDs of stakeholders assigned to the data domain',
    subdomains COMMENT 'List of GUIDs of sub-data domains that exist within this data domain',
    data_product_status COMMENT 'Status of the data product (DAAPSTATUS)',
    criticality COMMENT 'Criticality of the data product (DAAPCRITICALITY)',
    sensitivity COMMENT 'Sensitivity of the data product (DAAPSENSITIVITY)',
    visibility COMMENT 'Visibility of the data product (DAAPVISIBILITY)',
    input_port_guids COMMENT 'List of GUIDs for input ports of the data product (DAAPINPUTPORTGUIDS)',
    output_port_guids COMMENT 'List of GUIDs for output ports of the data product (DAAPOUTPUTPORTGUIDS)',
    data_domain COMMENT 'GUID of the data domain in which this data product exists (DATADOMAIN)',
    assets_dsl COMMENT 'Search DSL used to define which assets are part of this data product (DATAPRODUCTASSETSDSL)',
    assets_playbook_filter COMMENT 'Playbook filter used to define which assets are part of this data product (DATAPRODUCTASSETSFILTER)'
)
COMMENT 'Gold layer view providing Data Mesh details. This view consolidates metadata for DataDomain and DataProduct typedefs under the Data Mesh supertype.'
AS
SELECT
    guid                 AS guid,
    typename             AS asset_type,
    dataproducts         AS data_products,
    CAST(get(parentdomain, 0) AS STRING) AS parent_domain,
    stakeholders         AS stakeholders,
    subdomains           AS subdomains,
    NULL                 AS data_product_status,
    NULL                 AS criticality,
    NULL                 AS sensitivity,
    NULL                 AS visibility,
    NULL                 AS input_port_guids,
    NULL                 AS output_port_guids,
    NULL                 AS data_domain,
    NULL                 AS assets_dsl,
    NULL                 AS assets_playbook_filter
FROM datadomain
UNION ALL
SELECT
    guid                     AS guid,
    typename                 AS asset_type,
    NULL                     AS data_products,
    NULL                     AS parent_domain,
    NULL                     AS stakeholders,
    NULL                     AS subdomains,
    daapstatus               AS data_product_status,
    daapcriticality          AS criticality,
    daapsensitivity          AS sensitivity,
    daapvisibility           AS visibility,
    daapinputportguids       AS input_port_guids,
    daapoutputportguids      AS output_port_guids,
    CAST(get(datadomain, 0) AS STRING) AS data_domain,
    dataproductassetsdsl     AS assets_dsl,
    dataProductAssetsPlaybookFilter  AS assets_playbook_filter
FROM dataproduct;

CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.LINEAGE_PROCESSES (
    guid COMMENT 'The asset’s globally-unique identifier',
    type_name COMMENT 'The asset’s type (e.g., process, biprocess, columnprocess, dbtprocess, dbtcolumnprocess)',
    name COMMENT 'The asset’s name',
    qualified_name COMMENT 'The asset’s fully-qualified unique name',
    description COMMENT 'The asset’s description',
    status COMMENT 'The asset’s status (e.g., active, archived)',
    created_time COMMENT 'The time (epoch, milliseconds) at which the asset was created',
    updated_time COMMENT 'The time (epoch, milliseconds) at which the asset was last updated',
    created_by COMMENT 'The user or account that created the asset',
    updated_by COMMENT 'The user or account that last updated the asset',
    certificate_status COMMENT 'Certification status indicating trust or validation level of the process',
    connector_name COMMENT 'The type of connector through which this asset is accessible',
    connector_qualified_name COMMENT 'The unique, fully-qualified name of the connection through which this asset is accessible',
    connection_name COMMENT 'The name of the connection through which this asset is accessible',
    popularity_score COMMENT 'Popularity score representing usage or importance of the process',
    owner_users COMMENT 'List of users who own this asset',
    has_lineage COMMENT 'Indicates whether lineage information is available for this process',
    sql COMMENT 'The SQL transformation logic for this process',
    ast COMMENT 'Abstract Syntax Tree (AST) representation of the SQL or transformation logic',
    code COMMENT 'Non-SQL transformation code associated with the process',
    additional_etl_context COMMENT 'Additional ETL or execution context metadata for the process',
    inputs COMMENT 'List of GUIDs that this process takes as input',
    outputs COMMENT 'List of GUIDs that this process produces as output',
    process COMMENT 'The parent process associated with this asset (used primarily for column-level lineage)'
)
COMMENT 'Information about asset-level and column-level lineage processes in Atlan'
AS
SELECT
    guid,
    typename AS type_name,
    name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description) AS description,
    status,
    createtime AS created_time,
    updatetime AS updated_time,
    createdby AS created_by,
    updatedby AS updated_by,
    certificatestatus AS certificate_status,
    connectorname AS connector_name,
    connectionqualifiedname AS connector_qualified_name,
    connectionname AS connection_name,
    popularityscore AS popularity_score,
    ownerusers AS owner_users,
    haslineage AS has_lineage,
    sql,
    ast,
    code,
    additionalEtlContext AS additional_etl_context,
    inputs,
    outputs,
    NULL AS process
FROM process
UNION ALL
SELECT
    guid,
    typename AS type_name,
    name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description),
    status,
    createtime,
    updatetime,
    createdby,
    updatedby,
    certificatestatus,
    connectorname,
    connectionqualifiedname,
    connectionname,
    popularityscore,
    ownerusers,
    haslineage,
    sql,
    ast,
    code,
    additionalEtlContext,
    inputs,
    outputs,
    NULL AS process
FROM biprocess
UNION ALL
SELECT
    guid,
    typename AS type_name,
    name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description),
    status,
    createtime,
    updatetime,
    createdby,
    updatedby,
    certificatestatus,
    connectorname,
    connectionqualifiedname,
    connectionname,
    popularityscore,
    ownerusers,
    haslineage,
    sql,
    ast,
    code,
    additionalEtlContext,
    inputs,
    outputs,
    NULL AS process
FROM columnprocess
UNION ALL
SELECT
    guid,
    typename AS type_name,
    name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description),
    status,
    createtime,
    updatetime,
    createdby,
    updatedby,
    certificatestatus,
    connectorname,
    connectionqualifiedname,
    connectionname,
    popularityscore,
    ownerusers,
    haslineage,
    sql,
    ast,
    code,
    additionalEtlContext,
    inputs,
    outputs,
    NULL AS process
FROM dbtprocess
UNION ALL
SELECT
    guid,
    typename AS type_name,
    name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description),
    status,
    createtime,
    updatetime,
    createdby,
    updatedby,
    certificatestatus,
    connectorname,
    connectionqualifiedname,
    connectionname,
    popularityscore,
    ownerusers,
    haslineage,
    sql,
    ast,
    code,
    additionalEtlContext,
    inputs,
    outputs,
    process
FROM dbtcolumnprocess;

CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.GLOSSARY_DETAILS (
    guid COMMENT 'The asset’s globally-unique identifier',
    asset_type COMMENT 'E.g., Glossary, GlossaryTerm',
    name COMMENT 'E.g., Sales, Medical, Marketing',
    qualified_name COMMENT 'The unique qualified name of the asset',
    description COMMENT 'The asset’s description',
    status COMMENT 'The status of the asset',
    created_time COMMENT 'The time the asset was created',
    updated_time COMMENT 'The time the asset was last updated',
    created_by COMMENT 'The user who created the asset',
    updated_by COMMENT 'The user who last updated the asset',
    certificate_status COMMENT 'The certification status of the asset',
    connector_name COMMENT 'The name of the connector',
    connector_qualified_name COMMENT 'The qualified name of the connector',
    popularity_score COMMENT 'The popularity score of the asset',
    owner_users COMMENT 'The users who own the asset',
    has_lineage COMMENT 'Whether or not the asset has lineage',
    terms COMMENT 'List of terms that belong to the glossary or glossary category',
    categories COMMENT 'List of categories that belong to the glossary, or the glossary categories the term is attached to',
    assigned_entities COMMENT 'List of assets that the glossary term has been assigned to',
    readme_guid COMMENT 'The asset’s Readme guid',
    anchor_guid COMMENT 'The glossary guid that the term or category belongs to'
)
COMMENT 'Information about glossaries, glossary categories, and terms'
AS
SELECT
    guid AS guid,
    typename AS asset_type,
    name AS name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description) AS description,
    status AS status,
    createtime AS created_time,
    updatetime AS updated_time,
    createdby AS created_by,
    updatedby AS updated_by,
    certificatestatus AS certificate_status,
    connectorname AS connector_name,
    connectionqualifiedname AS connector_qualified_name,
    popularityscore AS popularity_score,
    ownerusers AS owner_users,
    haslineage AS has_lineage,
    terms AS terms,
    categories AS categories,
    NULL AS assigned_entities,
    CAST(get(readme, 0) AS STRING) AS readme_guid,
    NULL AS anchor_guid
FROM glossary
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    name AS name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description) AS description,
    status AS status,
    createtime AS created_time,
    updatetime AS updated_time,
    createdby AS created_by,
    updatedby AS updated_by,
    certificatestatus AS certificate_status,
    connectorname AS connector_name,
    connectionqualifiedname AS connector_qualified_name,
    popularityscore AS popularity_score,
    ownerusers AS owner_users,
    haslineage AS has_lineage,
    NULL AS terms,
    categories AS categories,
    assignedentities AS assigned_entities,
    CAST(get(readme, 0) AS STRING) AS readme_guid,
    CAST(get(anchor, 0) AS STRING) AS anchor_guid
FROM glossaryterm

UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    name AS name,
    qualifiedname AS qualified_name,
    COALESCE(userdescription, description) AS description,
    status AS status,
    createtime AS created_time,
    updatetime AS updated_time,
    createdby AS created_by,
    updatedby AS updated_by,
    certificatestatus AS certificate_status,
    connectorname AS connector_name,
    connectionqualifiedname AS connector_qualified_name,
    popularityscore AS popularity_score,
    ownerusers AS owner_users,
    haslineage AS has_lineage,
    terms AS terms,
    NULL AS categories,
    NULL AS assigned_entities,
    CAST(get(readme, 0) AS STRING) AS readme_guid,
    CAST(get(anchor, 0) AS STRING) AS anchor_guid
FROM glossarycategory;



CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.DATA_QUALITY_DETAILS (
    guid COMMENT 'The asset’s globally-unique identifier',
    asset_type COMMENT 'The type of asset',
    source_url COMMENT 'The source URL for this data quality check',
    anomalo_check_type COMMENT 'Type of Anomalo check',
    anomalo_check_category_type COMMENT 'Category type of the Anomalo check',
    anomalo_check_priority_level COMMENT 'Priority level of the Anomalo check',
    anomalo_check_status COMMENT 'Most recent status of the Anomalo check',
    anomalo_check_last_run_completed_at COMMENT 'Timestamp when the Anomalo check was last run',
    anomalo_check_linked_asset_qualified_name COMMENT 'Qualified name of the asset associated with the Anomalo check',
    soda_check_id COMMENT 'Identifier of the check in Soda',
    soda_check_definition COMMENT 'Definition of the Soda check',
    soda_check_evaluation_status COMMENT 'Most recent status of the Soda check',
    soda_check_last_scan_at COMMENT 'Timestamp when the Soda check was last run',
    soda_check_columns COMMENT 'List of columns associated with the Soda check',
    soda_check_assets COMMENT 'List of assets associated with the Soda check',
    mc_monitor_id COMMENT 'Identifier of the check in Monte Carlo',
    mc_monitor_type COMMENT 'Type of Monte Carlo monitor',
    mc_monitor_rule_type COMMENT 'Rule type of the Monte Carlo monitor',
    mc_monitor_priority COMMENT 'Priority level of the Monte Carlo monitor',
    mc_monitor_status COMMENT 'Most recent status of the Monte Carlo monitor',
    mc_monitor_rule_last_execution_time COMMENT 'Timestamp when the Monte Carlo monitor was last run',
    mc_monitor_assets COMMENT 'List of assets associated with the Monte Carlo monitor'
)
COMMENT 'All assets in Atlan that pertain to data quality, including Atlan-native and third-party data quality rules'
AS
SELECT
    guid AS guid,
    typename AS asset_type,
    sourceurl AS source_url,

    -- AnomaloCheck-specific columns
    anomalochecktype AS anomalo_check_type,
    anomalocheckcategorytype AS anomalo_check_category_type,
    anomalocheckprioritylevel AS anomalo_check_priority_level,
    anomalocheckstatus AS anomalo_check_status,
    anomalochecklastruncompletedat AS anomalo_check_last_run_completed_at,
    anomalochecklinkedassetqualifiedname AS anomalo_check_linked_asset_qualified_name,

    -- SodaCheck-specific columns (NULL for Anomalo)
    NULL AS soda_check_id,
    NULL AS soda_check_definition,
    NULL AS soda_check_evaluation_status,
    NULL AS soda_check_last_scan_at,
    NULL AS soda_check_columns,
    NULL AS soda_check_assets,

    -- MCMonitor-specific columns (NULL for Anomalo)
    NULL AS mc_monitor_id,
    NULL AS mc_monitor_type,
    NULL AS mc_monitor_rule_type,
    NULL AS mc_monitor_priority,
    NULL AS mc_monitor_status,
    NULL AS mc_monitor_rule_last_execution_time,
    NULL AS mc_monitor_assets
FROM anomalocheck

UNION ALL

SELECT
    guid AS guid,
    typename AS asset_type,
    sourceurl AS source_url,

    -- AnomaloCheck columns as NULL
    NULL, NULL, NULL, NULL, NULL, NULL,

    -- SodaCheck columns
    sodacheckid AS soda_check_id,
    sodacheckdefinition AS soda_check_definition,
    sodacheckevaluationstatus AS soda_check_evaluation_status,
    sodachecklastscanat AS soda_check_last_scan_at,
    sodacheckcolumns AS soda_check_columns,
    sodacheckassets AS soda_check_assets,

    -- MCMonitor columns as NULL
    NULL, NULL, NULL, NULL, NULL, NULL, NULL
FROM sodacheck

UNION ALL

SELECT
    guid AS guid,
    typename AS asset_type,
    sourceurl AS source_url,

    -- AnomaloCheck columns as NULL
    NULL, NULL, NULL, NULL, NULL, NULL,

    -- SodaCheck columns as NULL
    NULL, NULL, NULL, NULL, NULL, NULL,

    -- MCMonitor columns
    mcmonitorid AS mc_monitor_id,
    mcmonitortype AS mc_monitor_type,
    mcmonitorruletype AS mc_monitor_rule_type,
    mcmonitorpriority AS mc_monitor_priority,
    mcmonitorstatus AS mc_monitor_status,
    mcmonitorrulepreviousexecutiontime AS mc_monitor_rule_last_execution_time,
    mcmonitorassets AS mc_monitor_assets
FROM mcmonitor;


CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.PIPELINE_DETAILS 
(
    guid COMMENT 'The asset’s globally-unique identifier',
    asset_type COMMENT 'The asset’s type',
    input_guids_to_processes COMMENT 'Processes to which this asset is used as an input',
    output_guids_from_processes COMMENT 'Processes from which this asset is produced as output'
)
COMMENT 'All assets in Atlan that pertain to orchestration, such as ADF, Airflow, Dbt, Fivetran, Matillion etc.'
AS
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM adfactivity

UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM adfdataflow
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM adfdataset
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM adflinkedservice
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM adfpipeline
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM airflowdag
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM airflowtask
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtmodelcolumn
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtcolumnprocess
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtmetric
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtmodel
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtprocess
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtseed
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbtsource
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbttag

UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM dbttest
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM fivetranconnector
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM matillioncomponent
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM matilliongroup
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM matillionjob
UNION ALL
SELECT
    guid AS guid,
    typename AS asset_type,
    inputtoprocesses AS input_guids_to_processes,
    outputfromprocesses AS output_guids_from_processes
FROM matillionproject;


CREATE OR REPLACE VIEW ATLAN.ATLAN_GOLD.RELATIONAL_ASSET_DETAILS (
    guid COMMENT 'The asset’s globally-unique identifier',
    asset_type COMMENT 'The type of asset',
    source_read_query_cost COMMENT 'Total cost of read queries at source',
    source_total_cost COMMENT 'Total cost of all operations at source',
    source_cost_unit COMMENT 'The unit of measure for cost at source (e.g., credits)',
    column_datatype COMMENT 'Data type of this column',
    column_is_nullable COMMENT 'Whether or not the values in this column can be null',
    column_queries COMMENT 'Queries that access this column',
    column_recent_users COMMENT 'List of usernames of the most recent users who read this column',
    column_table_name COMMENT 'Table in which this column exists',
    column_total_read_count COMMENT 'Total count of all read operations at source',
    column_view_name COMMENT 'View in which this column exists',
    database_schemas COMMENT 'GUIDs for schemas that exist within this database',
    function_language COMMENT 'Language of this function',
    function_return_type COMMENT 'Data type of the value returned by the function',
    function_schema COMMENT 'Schema in which this function exists',
    function_type COMMENT 'Type of this function',
    materialised_view_columns COMMENT 'List of GUIDs of columns that exist within this materialised view',
    materialised_view_definition COMMENT 'Definition of this materialized view',
    procedure_definition COMMENT 'Definition of this procedure',
    procedure_schema COMMENT 'Schema in which this procedure exists',
    query_columns COMMENT 'List of GUIDs for columns this query accesses',
    query_parent COMMENT 'Collection or folder in which this query exists',
    query_raw_query_text COMMENT 'Raw query text',
    query_tables COMMENT 'List of GUIDs for tables this query accesses',
    query_views COMMENT 'List of GUIDs for views this query accesses',
    schema_database_name COMMENT 'Database in which this schema exists',
    schema_materialised_views COMMENT 'GUIDs for materialised views that exist within this schema',
    schema_procedures COMMENT 'GUIDs for stored procedures that exist within this schema',
    schema_tables COMMENT 'GUIDs for tables that exist within this schema',
    schema_views COMMENT 'GUIDs for views that exist within this schema',
    table_columns COMMENT 'List of GUIDs of columns that exist within this table',
    table_column_count COMMENT 'Number of columns that exist within this table',
    table_queries COMMENT 'Queries that access this table',
    table_recent_users COMMENT 'List of usernames of the most recent users who read this table',
    table_row_count COMMENT 'Number of rows in this table',
    table_size_bytes COMMENT 'Size of this table, in bytes',
    table_total_read_count COMMENT 'Total count of all read operations at source',
    view_columns COMMENT 'List of GUIDs of columns that exist within this view',
    view_definition COMMENT 'SQL definition of this view',
    view_queries COMMENT 'Queries that access this view',
    view_recent_users COMMENT 'List of usernames of the most recent users who read this view',
    view_total_read_count COMMENT 'Total count of all read operations at source.'
)
COMMENT 'A unified relational asset view that consolidates metadata for Databases, Schemas, Tables, Views, Columns, Queries, Materialized Views, Functions, and Procedures into a single registry with domain-specific attributes'
AS

SELECT
    guid, typename, sourcereadquerycost, sourcetotalcost, sourcecostunit, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 
    schemas, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL
FROM database
UNION ALL
SELECT
    guid, typename, sourcereadquerycost, sourcetotalcost, sourcecostunit,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
    NULL, NULL, NULL, databasename, materialisedviews, procedures, tables, views, NULL, NULL,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL
FROM schema
UNION ALL
SELECT
    guid, typename, sourcereadquerycost, sourcetotalcost, sourcecostunit,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
    NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
